                            uint8_t *data, size_t size)

{

    AVPacketSideData *sd, *tmp;

    int i;



    for (i = 0; i < st->nb_side_data; i++) {

        sd = &st->side_data[i];



        if (sd->type == type) {

            av_freep(&sd->data);

            sd->data = data;

            sd->size = size;

